/* eslint-disable no-restricted-globals */

// This service worker is processed by workbox-webpack-plugin during build.
// workbox-webpack-plugin injects the precache manifest at build time,
// so all static assets will be cached and available offline.

import { clientsClaim } from 'workbox-core';
import { precacheAndRoute, createHandlerBoundToURL } from 'workbox-precaching';
import { registerRoute } from 'workbox-routing';

clientsClaim();

// Precache all of the assets generated by the build.
// The manifest is injected automatically by workbox-webpack-plugin.
precacheAndRoute(self.__WB_MANIFEST);

// The default CRA navigation route handler — serves index.html for
// all navigations, enabling client-side routing to work offline.
const handler = createHandlerBoundToURL('/index.html');
registerRoute(
  ({ request, url }) =>
    request.mode === 'navigate' &&
    !url.pathname.startsWith('/_') &&
    url.pathname.indexOf('.') === -1,
  handler
);

